var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            // Grid
            ctx.strokeStyle = '#E0E0E0';
            ctx.lineWidth = 1;
            for (let i = 0; i <= 10; i++) {
              ctx.beginPath();
              ctx.moveTo(i * (W/10), 0);
              ctx.lineTo(i * (W/10), H);
              ctx.stroke();
              ctx.beginPath();
              ctx.moveTo(0, i * (H/10));
              ctx.lineTo(W, i * (H/10));
              ctx.stroke();
            }

            // Ball falling: visual duration (not literal g=9.8 in pixels, which
            // would take ~11s to cross the screen and look frozen). Loops.
            const fallDuration = 1.5;
            const cycle = fallDuration + 0.8;
            elapsed += Math.min(dt || 0, 0.05);
            if (elapsed > cycle) { elapsed -= cycle; }
            const time = Math.min(elapsed, fallDuration);
            const progress = time / fallDuration;
            const startY = 50;
            const groundY = H - 30;
            const yPos = startY + (groundY - startY) * progress * progress;

            // Draw ball
            ctx.fillStyle = '#DC2626';
            ctx.beginPath();
            ctx.arc(W/2, yPos, 15, 0, Math.PI * 2);
            ctx.fill();

            // Position text
            ctx.fillStyle = '#333';
            ctx.font = '14px Arial';
            ctx.fillText('y = ½gt²', 10, 30);
            ctx.fillText('v = gt', 10, 50);

            // Velocity arrow (grows with speed, i.e. with progress)
            const arrowLen = progress * 100;
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(W/2 + 30, yPos);
            ctx.lineTo(W/2 + 30, yPos + arrowLen);
            ctx.stroke();

            // Arrowhead
            ctx.beginPath();
            ctx.moveTo(W/2 + 30, yPos + arrowLen);
            ctx.lineTo(W/2 + 25, yPos + arrowLen - 10);
            ctx.lineTo(W/2 + 35, yPos + arrowLen - 10);
            ctx.closePath();
            ctx.fillStyle = '#3B82F6';
            ctx.fill();
          }
        };
